#!/bin/bash
# postgres-init.sh — Initialization script for pre-migrated Sentry Postgres
#
# This script runs inside docker-entrypoint-initdb.d/ when the Postgres
# container starts for the first time. It:
#   1. Creates all 4 Sentry databases
#   2. Restores pre-built SQL dumps into each database
#
# The dumps are generated by build-postgres-image.sh and baked into the image.

set -euo pipefail

DUMPS_DIR="/docker-entrypoint-initdb.d/dumps"

echo "==> Creating Sentry databases..."

# Create the 4 databases Sentry uses in development
for db in sentry control region secondary; do
    echo "    Creating database: ${db}"
    psql -v ON_ERROR_STOP=1 --username "$POSTGRES_USER" <<-SQL
        SELECT 'CREATE DATABASE ${db}'
        WHERE NOT EXISTS (SELECT FROM pg_database WHERE datname = '${db}')
        \gexec
SQL
done

echo "==> Restoring database dumps..."

# Restore dumps if they exist
for db in sentry control region secondary; do
    dump_file="${DUMPS_DIR}/${db}.sql"
    if [ -f "${dump_file}" ]; then
        echo "    Restoring ${db} from ${dump_file}..."
        psql -v ON_ERROR_STOP=1 --username "$POSTGRES_USER" --dbname "${db}" < "${dump_file}"
        echo "    Done restoring ${db}"
    else
        echo "    No dump found for ${db}, skipping (empty database)"
    fi
done

echo "==> Database initialization complete"
echo "    Databases: sentry, control, region, secondary"

# Print migration counts for verification
for db in sentry control region secondary; do
    count=$(psql -t --username "$POSTGRES_USER" --dbname "${db}" \
        -c "SELECT COUNT(*) FROM django_migrations" 2>/dev/null || echo "0")
    echo "    ${db}: ${count} migrations applied"
done
